import{_ as w,z as y,j as f,k as q,a6 as x,a as r,b as o,a5 as u,f as h,n as k,o as l}from"./index.3affe3a0.js";const T={class:"help-container"},S={key:0,class:"toc"},A={key:1,class:"help-footer"},P={__name:"pixelPower",setup(W){const p=y(),c=f(p.query.autoScroll==="true");let d=null;const n=e=>{var a;if(!c.value&&e.target.tagName==="A"&&((a=e.target.getAttribute("href"))==null?void 0:a.startsWith("#"))){e.preventDefault();const s=e.target.getAttribute("href").slice(1),t=document.getElementById(s);t&&t.scrollIntoView({behavior:"smooth",block:"start"})}},g=()=>{const e=document.querySelector(".help-page");if(!e)return;let a=1,s=1,t=0;const v=360,i=()=>{const m=e.scrollHeight-e.clientHeight,b=e.scrollTop;if(t>0){t--,d=requestAnimationFrame(i);return}a===1?(e.scrollTop+=s,b>=m-10&&(t=v,a=-1,s=100)):(e.scrollTop-=s,b<=10&&(t=v,a=1,s=1)),d=requestAnimationFrame(i)};d=requestAnimationFrame(i)};return q(()=>{document.addEventListener("click",n),c.value&&setTimeout(g,1e3)}),x(()=>{document.removeEventListener("click",n),d&&cancelAnimationFrame(d)}),(e,a)=>(l(),r("div",{class:k(["help-page",{"auto-scroll-mode":c.value}])},[o("div",T,[a[2]||(a[2]=o("header",{id:"top",class:"help-header"},[o("h1",{class:"crt-text-green"},"\u{1F3A8} PIXEL POWER: AI ART COLLAB"),o("p",{class:"subtitle"},"Create Amazing AI Art Together!")],-1)),c.value?h("",!0):(l(),r("nav",S,[...a[0]||(a[0]=[u('<h2 class="crt-text-yellow" data-v-1c5eb944>Quick Navigation</h2><ul data-v-1c5eb944><li data-v-1c5eb944><a href="#basics" data-v-1c5eb944>Game Basics</a></li><li data-v-1c5eb944><a href="#commands" data-v-1c5eb944>How to Play</a></li><li data-v-1c5eb944><a href="#limits" data-v-1c5eb944>Submission Limits</a></li><li data-v-1c5eb944><a href="#dictionary" data-v-1c5eb944>Word Rules</a></li><li data-v-1c5eb944><a href="#scoring" data-v-1c5eb944>Scrabble Scoring</a></li><li data-v-1c5eb944><a href="#display" data-v-1c5eb944>Word Display</a></li><li data-v-1c5eb944><a href="#generation" data-v-1c5eb944>Image Generation</a></li><li data-v-1c5eb944><a href="#rewards" data-v-1c5eb944>Rewards</a></li><li data-v-1c5eb944><a href="#tips" data-v-1c5eb944>Pro Tips</a></li></ul>',2)])])),a[3]||(a[3]=u('<section id="basics" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u{1F4D6} Game Basics</h2><div class="content-block" data-v-1c5eb944><h3 data-v-1c5eb944>What is Pixel Power?</h3><p data-v-1c5eb944>Pixel Power is a collaborative AI art creation game where the Twitch community works together to generate unique images! Submit words in chat, and when 32 words are collected (or 24 hours pass), an AI will create a stunning video game-style artwork based on ALL the submitted words combined!</p><h3 data-v-1c5eb944>How It Works</h3><ol data-v-1c5eb944><li data-v-1c5eb944><strong data-v-1c5eb944>Submit Words:</strong> Type <code class="crt-text-yellow" data-v-1c5eb944>!art [word]</code> in chat</li><li data-v-1c5eb944><strong data-v-1c5eb944>Collection Builds:</strong> Watch as words accumulate (0/32)</li><li data-v-1c5eb944><strong data-v-1c5eb944>Words Display:</strong> See each word&#39;s definition for 1 minute</li><li data-v-1c5eb944><strong data-v-1c5eb944>Image Generated:</strong> AI creates art when 32 words are reached OR 24 hours pass</li><li data-v-1c5eb944><strong data-v-1c5eb944>Earn Rewards:</strong> Get zCubes based on your contribution!</li></ol><div class="pro-tip" data-v-1c5eb944><strong data-v-1c5eb944>\u{1F4A1} Cool Feature:</strong> The game runs on a 24-hour cycle. If 32 words aren&#39;t collected in time, the AI generates an image from whatever words were submitted, then resets for a new session! </div></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section><section id="commands" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u{1F4AC} How to Play</h2><div class="command-list" data-v-1c5eb944><div class="command-item" data-v-1c5eb944><h3 data-v-1c5eb944><code class="crt-text-yellow" data-v-1c5eb944>!art [word]</code></h3><p data-v-1c5eb944>Submit a single dictionary word to the collection</p><p data-v-1c5eb944><strong data-v-1c5eb944>Examples:</strong></p><ul data-v-1c5eb944><li data-v-1c5eb944><code data-v-1c5eb944>!art dragon</code> - Submit the word &quot;dragon&quot;</li><li data-v-1c5eb944><code data-v-1c5eb944>!art sword</code> - Submit the word &quot;sword&quot;</li><li data-v-1c5eb944><code data-v-1c5eb944>!art crystal</code> - Submit the word &quot;crystal&quot;</li></ul><div class="note" data-v-1c5eb944><strong data-v-1c5eb944>\u26A0\uFE0F Important:</strong> Only ONE word at a time! Words like &quot;fire dragon&quot; won&#39;t work. Submit them separately: <code data-v-1c5eb944>!art fire</code> then <code data-v-1c5eb944>!art dragon</code></div></div><div class="command-item" data-v-1c5eb944><h3 data-v-1c5eb944>What Happens After Submission?</h3><ol data-v-1c5eb944><li data-v-1c5eb944><strong data-v-1c5eb944>Validation:</strong> Word is checked against dictionary API</li><li data-v-1c5eb944><strong data-v-1c5eb944>Scoring:</strong> Scrabble score is calculated (see Scoring section)</li><li data-v-1c5eb944><strong data-v-1c5eb944>Display:</strong> Word appears on stream with full definition for 60 seconds</li><li data-v-1c5eb944><strong data-v-1c5eb944>Collection Update:</strong> Counter updates (e.g., 15/32 words)</li></ol><div class="pro-tip" data-v-1c5eb944><strong data-v-1c5eb944>\u{1F4A1} Pro Tip:</strong> While your word is being displayed, the word cloud is hidden. After 60 seconds, the display switches back to show ALL submitted words in the cloud! </div></div></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section><section id="limits" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u23F1\uFE0F Submission Limits</h2><div class="content-block" data-v-1c5eb944><h3 data-v-1c5eb944>Per-User Limits</h3><p data-v-1c5eb944>To keep things fair and give everyone a chance to contribute:</p><div class="limit-box hourly" data-v-1c5eb944><h4 data-v-1c5eb944>\u{1F550} Hourly Limit</h4><ul data-v-1c5eb944><li data-v-1c5eb944><strong data-v-1c5eb944>3 words per hour</strong> per user</li><li data-v-1c5eb944>Resets every 60 minutes from your first word</li><li data-v-1c5eb944>Timer is tracked individually for each user</li></ul><div class="example" data-v-1c5eb944><strong data-v-1c5eb944>Example:</strong><ul data-v-1c5eb944><li data-v-1c5eb944>\u{1F550} 12:00 PM - Submit &quot;dragon&quot; (2 left this hour)</li><li data-v-1c5eb944>\u{1F550} 12:15 PM - Submit &quot;sword&quot; (1 left this hour)</li><li data-v-1c5eb944>\u{1F550} 12:30 PM - Submit &quot;fire&quot; (0 left this hour)</li><li data-v-1c5eb944>\u{1F6AB} 12:45 PM - Try &quot;crystal&quot; \u2192 \u274C Hourly limit reached!</li><li data-v-1c5eb944>\u2705 1:00 PM - Your hour resets, can submit 3 more!</li></ul></div></div><div class="limit-box daily" data-v-1c5eb944><h4 data-v-1c5eb944>\u{1F4C5} Daily Limit</h4><ul data-v-1c5eb944><li data-v-1c5eb944><strong data-v-1c5eb944>12 words per day</strong> per user</li><li data-v-1c5eb944>Resets when the global 24-hour timer expires</li><li data-v-1c5eb944>Shared across all users (everyone resets together)</li></ul><div class="example" data-v-1c5eb944><strong data-v-1c5eb944>Example:</strong><ul data-v-1c5eb944><li data-v-1c5eb944>If the session started at 3:00 PM yesterday</li><li data-v-1c5eb944>You can submit up to 12 words total until 3:00 PM today</li><li data-v-1c5eb944>At 3:00 PM today, everyone&#39;s daily count resets to 0</li></ul></div></div><h3 data-v-1c5eb944>What Happens When You Hit a Limit?</h3><div class="limit-messages" data-v-1c5eb944><div class="message-box" data-v-1c5eb944><code class="crt-text-red" data-v-1c5eb944>\u26A0\uFE0F @username hourly limit reached, wait 15 minutes</code><p data-v-1c5eb944>You&#39;ve used all 3 hourly submissions. The bot tells you how long until your hourly timer resets.</p></div><div class="message-box" data-v-1c5eb944><code class="crt-text-red" data-v-1c5eb944>\u26A0\uFE0F @username daily limit reached, wait 6 hours</code><p data-v-1c5eb944>You&#39;ve used all 12 daily submissions. The bot tells you how long until the global timer resets.</p></div></div></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section><section id="dictionary" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u{1F4DA} Word Rules</h2><div class="content-block" data-v-1c5eb944><h3 data-v-1c5eb944>Valid Words</h3><p data-v-1c5eb944>All words are validated using a real English dictionary API. To be accepted, your word must:</p><ul data-v-1c5eb944><li data-v-1c5eb944>\u2705 Be a real English word</li><li data-v-1c5eb944>\u2705 Be found in the dictionary</li><li data-v-1c5eb944>\u2705 Be a single word (no spaces)</li><li data-v-1c5eb944>\u2705 Be spelled correctly</li></ul><h3 data-v-1c5eb944>Invalid Words</h3><ul data-v-1c5eb944><li data-v-1c5eb944>\u274C Multiple words: &quot;fire dragon&quot; \u2192 Use separately</li><li data-v-1c5eb944>\u274C Misspellings: &quot;dragn&quot; \u2192 Won&#39;t be accepted</li><li data-v-1c5eb944>\u274C Made-up words: &quot;flibbertigibbet&quot; \u2192 Depends on dictionary!</li><li data-v-1c5eb944>\u274C Numbers/symbols: &quot;dr4gon&quot; \u2192 Letters only</li></ul><div class="pro-tip" data-v-1c5eb944><strong data-v-1c5eb944>\u{1F4A1} Fun Fact:</strong> The dictionary includes some quirky but real words! Try &quot;defenestration&quot; (throwing someone out a window) or &quot;petrichor&quot; (the smell of rain on dry earth). </div><h3 data-v-1c5eb944>What Happens if Word is Invalid?</h3><div class="message-box" data-v-1c5eb944><code class="crt-text-red" data-v-1c5eb944>\u{1F4D6} @username &quot;dragn&quot; is not a valid dictionary word. Try another!</code><p data-v-1c5eb944>The bot will let you know, and your submission won&#39;t count against your limits.</p></div></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section><section id="scoring" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u{1F3AF} Scrabble Scoring</h2><div class="content-block" data-v-1c5eb944><h3 data-v-1c5eb944>How Scoring Works</h3><p data-v-1c5eb944>Each word earns a Scrabble score based on the letter values. This affects your share of the rewards!</p><div class="score-table" data-v-1c5eb944><h4 data-v-1c5eb944>Letter Values</h4><table data-v-1c5eb944><tr data-v-1c5eb944><th data-v-1c5eb944>Points</th><th data-v-1c5eb944>Letters</th></tr><tr data-v-1c5eb944><td class="score" data-v-1c5eb944>1</td><td data-v-1c5eb944>A, E, I, O, U, L, N, S, T, R</td></tr><tr data-v-1c5eb944><td class="score" data-v-1c5eb944>2</td><td data-v-1c5eb944>D, G</td></tr><tr data-v-1c5eb944><td class="score" data-v-1c5eb944>3</td><td data-v-1c5eb944>B, C, M, P</td></tr><tr data-v-1c5eb944><td class="score" data-v-1c5eb944>4</td><td data-v-1c5eb944>F, H, V, W, Y</td></tr><tr data-v-1c5eb944><td class="score" data-v-1c5eb944>5</td><td data-v-1c5eb944>K</td></tr><tr data-v-1c5eb944><td class="score" data-v-1c5eb944>8</td><td data-v-1c5eb944>J, X</td></tr><tr data-v-1c5eb944><td class="score" data-v-1c5eb944>10</td><td data-v-1c5eb944>Q, Z</td></tr></table></div><h3 data-v-1c5eb944>Scoring Examples</h3><div class="score-examples" data-v-1c5eb944><div class="score-example" data-v-1c5eb944><strong data-v-1c5eb944>&quot;DRAGON&quot;</strong><p data-v-1c5eb944>D(2) + R(1) + A(1) + G(2) + O(1) + N(1) = <span class="crt-text-yellow" data-v-1c5eb944>8 points</span></p></div><div class="score-example" data-v-1c5eb944><strong data-v-1c5eb944>&quot;QUEST&quot;</strong><p data-v-1c5eb944>Q(10) + U(1) + E(1) + S(1) + T(1) = <span class="crt-text-yellow" data-v-1c5eb944>14 points</span></p></div><div class="score-example" data-v-1c5eb944><strong data-v-1c5eb944>&quot;ZEPHYR&quot;</strong><p data-v-1c5eb944>Z(10) + E(1) + P(3) + H(4) + Y(4) + R(1) = <span class="crt-text-yellow" data-v-1c5eb944>23 points!</span></p></div></div><div class="pro-tip" data-v-1c5eb944><strong data-v-1c5eb944>\u{1F4A1} Strategy:</strong> Higher-value letters (Q, Z, X, J) give you more points, but they&#39;re harder to use! Balance creativity with point value for maximum rewards. </div></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section><section id="display" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u{1F4FA} Word Display</h2><div class="content-block" data-v-1c5eb944><h3 data-v-1c5eb944>Two Display Modes</h3><p data-v-1c5eb944>The overlay automatically switches between two views:</p><div class="display-modes" data-v-1c5eb944><div class="display-mode" data-v-1c5eb944><h4 class="crt-text-cyan" data-v-1c5eb944>\u{1F4D6} Dictionary View</h4><p data-v-1c5eb944><strong data-v-1c5eb944>When:</strong> A word is being displayed (60 seconds)</p><p data-v-1c5eb944><strong data-v-1c5eb944>Shows:</strong></p><ul data-v-1c5eb944><li data-v-1c5eb944>\u{1F464} Submitter&#39;s avatar and name</li><li data-v-1c5eb944>\u{1F4DD} The word (large, glowing text)</li><li data-v-1c5eb944>\u{1F50A} Pronunciation guide (phonetic)</li><li data-v-1c5eb944>\u{1F4DA} Definition(s) from dictionary</li><li data-v-1c5eb944>\u{1F4AC} Example sentences</li><li data-v-1c5eb944>\u{1F3AF} Scrabble score</li></ul></div><div class="display-mode" data-v-1c5eb944><h4 class="crt-text-green" data-v-1c5eb944>\u2601\uFE0F Word Cloud View</h4><p data-v-1c5eb944><strong data-v-1c5eb944>When:</strong> No word is being displayed</p><p data-v-1c5eb944><strong data-v-1c5eb944>Shows:</strong></p><ul data-v-1c5eb944><li data-v-1c5eb944>\u2601\uFE0F All submitted words in a cloud</li><li data-v-1c5eb944>\u{1F4CA} Progress circle (X/32 words)</li><li data-v-1c5eb944>\u23F0 Time remaining until generation</li><li data-v-1c5eb944>\u{1F4C8} Collection progress messages</li></ul></div></div><h3 data-v-1c5eb944>Display Flow</h3><ol data-v-1c5eb944><li data-v-1c5eb944>User submits word via <code data-v-1c5eb944>!art dragon</code></li><li data-v-1c5eb944>Word is validated and scored</li><li data-v-1c5eb944>Dictionary view appears for 60 seconds</li><li data-v-1c5eb944>View switches back to word cloud automatically</li><li data-v-1c5eb944>Process repeats for each new word</li></ol><div class="note" data-v-1c5eb944><strong data-v-1c5eb944>\u{1F4FA} Overlay Note:</strong> This is a passive display - viewers don&#39;t interact with the overlay itself, only through Twitch chat commands! </div></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section><section id="generation" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u{1F3A8} Image Generation</h2><div class="content-block" data-v-1c5eb944><h3 data-v-1c5eb944>When Does Generation Happen?</h3><p data-v-1c5eb944>AI image generation is triggered by ONE of these conditions:</p><div class="trigger-conditions" data-v-1c5eb944><div class="trigger" data-v-1c5eb944><h4 class="crt-text-yellow" data-v-1c5eb944>\u{1F3AF} 32 Words Collected</h4><p data-v-1c5eb944>When the 32nd word is submitted, image generation starts immediately!</p></div><div class="trigger" data-v-1c5eb944><h4 class="crt-text-cyan" data-v-1c5eb944>\u23F0 24-Hour Timer Expires</h4><p data-v-1c5eb944>If 32 words aren&#39;t reached in 24 hours, the AI generates from whatever words are available (even if just 5 or 10 words!).</p></div></div><h3 data-v-1c5eb944>The Generation Process</h3><ol data-v-1c5eb944><li data-v-1c5eb944><strong data-v-1c5eb944>Collection Completes:</strong> 32 words OR timer expires</li><li data-v-1c5eb944><strong data-v-1c5eb944>Prompt Building:</strong> All words combined into AI prompt</li><li data-v-1c5eb944><strong data-v-1c5eb944>AI Generation:</strong> Stable Diffusion creates the image</li><li data-v-1c5eb944><strong data-v-1c5eb944>Style Applied:</strong> &quot;video game art, concept art, cinematic lighting&quot;</li><li data-v-1c5eb944><strong data-v-1c5eb944>Display:</strong> Generated image appears in carousel</li><li data-v-1c5eb944><strong data-v-1c5eb944>Reset:</strong> New session begins with 0/32 words!</li></ol><h3 data-v-1c5eb944>What Makes the Art Unique?</h3><p data-v-1c5eb944>The AI combines ALL submitted words into a single coherent image with these characteristics:</p><ul data-v-1c5eb944><li data-v-1c5eb944>\u{1F3AE} Video game art style</li><li data-v-1c5eb944>\u2728 Cinematic lighting and atmosphere</li><li data-v-1c5eb944>\u{1F5BC}\uFE0F Ultra-detailed, intricate elements</li><li data-v-1c5eb944>\u{1F3AD} Dramatic composition</li><li data-v-1c5eb944>\u{1F308} Rich colors and depth of field</li></ul><div class="example" data-v-1c5eb944><strong data-v-1c5eb944>Example Prompt:</strong><p data-v-1c5eb944>If words submitted are: dragon, sword, crystal, fire, castle...</p><p class="crt-text-cyan" data-v-1c5eb944>&quot;dragon, sword, crystal, fire, castle, video game art, concept art, game asset, rendered in Unreal Engine, cinematic lighting, dramatic atmosphere, masterpiece, best quality, ultra detailed&quot;</p></div><div class="pro-tip" data-v-1c5eb944><strong data-v-1c5eb944>\u{1F4A1} Collaboration Tip:</strong> Coordinate with other viewers! Plan themed collections like &quot;underwater adventure&quot; or &quot;space exploration&quot; for cohesive, amazing results! </div></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section><section id="rewards" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u{1F4B0} Rewards &amp; zCubes</h2><div class="content-block" data-v-1c5eb944><h3 data-v-1c5eb944>How Rewards Work</h3><p data-v-1c5eb944>Contributors earn zCubes based on their Scrabble score percentage of the total!</p><h3 data-v-1c5eb944>Reward Calculation</h3><div class="formula" data-v-1c5eb944><p data-v-1c5eb944><strong data-v-1c5eb944>Your zCubes</strong> = Total Pool \xD7 (Your Score \xF7 Total Score)</p></div><h3 data-v-1c5eb944>Example Scenario</h3><div class="reward-example" data-v-1c5eb944><p data-v-1c5eb944><strong data-v-1c5eb944>Session completes with 10 words:</strong></p><ul data-v-1c5eb944><li data-v-1c5eb944>User A submitted 3 words: 25 points total</li><li data-v-1c5eb944>User B submitted 4 words: 30 points total</li><li data-v-1c5eb944>User C submitted 3 words: 20 points total</li><li data-v-1c5eb944><strong data-v-1c5eb944>Total points: 75</strong></li></ul><p data-v-1c5eb944><strong data-v-1c5eb944>Reward pool: 500 zCubes</strong></p><div class="reward-split" data-v-1c5eb944><div class="user-reward" data-v-1c5eb944><strong data-v-1c5eb944>User A:</strong><p data-v-1c5eb944>500 \xD7 (25 \xF7 75) = <span class="crt-text-yellow" data-v-1c5eb944>167 zCubes</span></p></div><div class="user-reward" data-v-1c5eb944><strong data-v-1c5eb944>User B:</strong><p data-v-1c5eb944>500 \xD7 (30 \xF7 75) = <span class="crt-text-yellow" data-v-1c5eb944>200 zCubes</span></p></div><div class="user-reward" data-v-1c5eb944><strong data-v-1c5eb944>User C:</strong><p data-v-1c5eb944>500 \xD7 (20 \xF7 75) = <span class="crt-text-yellow" data-v-1c5eb944>133 zCubes</span></p></div></div></div><div class="pro-tip" data-v-1c5eb944><strong data-v-1c5eb944>\u{1F4A1} Reward Strategy:</strong> Multiple small words OR few high-value words? Both can work! A single &quot;QUIZ&quot; (22 points) could be worth more than three simple words like &quot;CAT&quot; (5 points). </div><h3 data-v-1c5eb944>When Are Rewards Distributed?</h3><p data-v-1c5eb944>Rewards are calculated and distributed automatically when the image is generated!</p></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section><section id="tips" class="help-section" data-v-1c5eb944><h2 class="crt-text-green" data-v-1c5eb944>\u{1F3C6} Pro Tips &amp; Strategy</h2><div class="tips-grid" data-v-1c5eb944><div class="tip-card" data-v-1c5eb944><h3 data-v-1c5eb944>\u{1F4DD} Use High-Value Letters</h3><p data-v-1c5eb944>Words with Q, Z, X, J earn more points! &quot;JAZZ&quot; (29 points) beats &quot;SONG&quot; (5 points).</p></div><div class="tip-card" data-v-1c5eb944><h3 data-v-1c5eb944>\u{1F3AD} Theme Your Words</h3><p data-v-1c5eb944>Coordinate with chat! Themed collections create better, more cohesive AI art.</p></div><div class="tip-card" data-v-1c5eb944><h3 data-v-1c5eb944>\u23F0 Use Your Hourly Limit Wisely</h3><p data-v-1c5eb944>You get 3 words per hour. Spread them out or use them all at once - your choice!</p></div><div class="tip-card" data-v-1c5eb944><h3 data-v-1c5eb944>\u{1F31F} Be Creative</h3><p data-v-1c5eb944>Don&#39;t just use common words! &quot;ETHEREAL&quot; or &quot;LUMINOUS&quot; make for better art than &quot;THING&quot; or &quot;STUFF&quot;.</p></div><div class="tip-card" data-v-1c5eb944><h3 data-v-1c5eb944>\u{1F4DA} Expand Your Vocabulary</h3><p data-v-1c5eb944>Every word is shown with its definition. Learn new words while playing!</p></div><div class="tip-card" data-v-1c5eb944><h3 data-v-1c5eb944>\u{1F91D} Collaborate</h3><p data-v-1c5eb944>Discuss in chat! Build on others&#39; words to create a cohesive concept.</p></div><div class="tip-card" data-v-1c5eb944><h3 data-v-1c5eb944>\u{1F3A8} Visual Thinking</h3><p data-v-1c5eb944>Think about how words will look combined. &quot;DRAGON&quot; + &quot;FIRE&quot; + &quot;MOUNTAIN&quot; = Epic scene!</p></div><div class="tip-card" data-v-1c5eb944><h3 data-v-1c5eb944>\u26A1 Be Quick but Thoughtful</h3><p data-v-1c5eb944>Don&#39;t waste submissions on low-value, common words when you have limited tries!</p></div></div><a href="#top" class="back-to-top" data-v-1c5eb944>\u2191 Back to Top</a></section>',9)),c.value?h("",!0):(l(),r("footer",A,[...a[1]||(a[1]=[o("p",{class:"crt-text-green"},"Ready to create amazing art together? Jump in chat and type !art [word]! \u{1F3A8}\u2728",-1),o("p",null,[o("a",{href:"/art",class:"back-link"},"\u2190 Back to Pixel Power")],-1)])]))])],2))}},C=w(P,[["__scopeId","data-v-1c5eb944"]]);export{C as default};
